// 【VIP规则：无效做种极限清理】
(maindata, torrent) => {
  const categoryList = ["不删", "keep", "养老"];
  const { state, upspeed, category, completedTime } = torrent.originProp;

  if (categoryList.indexOf(category) !== -1) return false;

  if (moment().hour() >= 0 && moment().hour() <= 8) return false;

  // 已经下完但分享率还没到3的种，如果下完过了1个半小时，且当前上传速度低于 1MB/s 了，直接杀掉腾硬盘
  if (
    (state === "uploading" || state === "stalledUP") &&
    completedTime > 0 && 
    (moment().unix() - completedTime >= 5400) &&
    upspeed <= util.calSize(1, "MiB") // 从原来的 512KB/s 提高到了 1MB/s
  ) {
    return true; 
  }

  return false;
};
